// Requires: NODE_FUNCTION_ALLOW_BUILTIN=fs,path in n8n Docker environment
// Requires: KYROS_KNOWLEDGE_PATH env var pointing to knowledge/public/ mount path
const fs = require('fs');
const path = require('path');

const knowledgePath = $env.KYROS_KNOWLEDGE_PATH || '/opt/kyros/knowledge/public';
let wikiContent = '';
let fileCount = 0;
let loadedAt = new Date().toISOString();

try {
  const files = fs.readdirSync(knowledgePath)
    .filter(f => f.endsWith('.md'))
    .sort();
  fileCount = files.length;
  wikiContent = files.map(f => {
    const raw = fs.readFileSync(path.join(knowledgePath, f), 'utf8');
    return '### ' + f + '\n' + raw;
  }).join('\n\n---\n\n');
} catch(err) {
  wikiContent = '[Knowledge base temporarily unavailable. Please apologise and ask the customer to direct questions to the team member at the desk.]';
}

return [{ json: { wiki_content: wikiContent, file_count: fileCount, wiki_version: '1.0.0', loaded_at: loadedAt } }];
